// No meetings found - just exit gracefully
return [{
  json: {
    success: true,
    message: 'No meetings require reminders at this time',
    timestamp: new Date().toISOString()
  }
}];

const meeting = $input.first().json;

// Format date/time for display
const meetingDateTime = new Date(meeting.date_time);
const dateStr = meetingDateTime.toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});
const timeStr = meetingDateTime.toLocaleTimeString('en-US', {
  hour: '2-digit',
  minute: '2-digit',
  hour12: true
});

// Clean phone numbers (remove + if present)
const cleanPhone = (phone) => {
  if (!phone) return null;
  return phone.replace(/\+/g, '');
};

const schedulerPhone = cleanPhone(meeting.scheduler_phone);
const contactPhone = cleanPhone(meeting.contact_phone);

// Message for the scheduler
const schedulerMessage = `⏰ **Meeting Reminder**\n\nYour meeting is starting in 30 minutes!\n\n📅 **${meeting.title}**\n👤 With: ${meeting.contact_name}\n🕐 Time: ${dateStr} at ${timeStr}\n📍 Location: ${meeting.location}\n📋 Purpose: ${meeting.purpose}\n\nPlease prepare accordingly.`;

// Message for the contact/end-user
const contactMessage = `⏰ **Meeting Reminder**\n\nYour meeting is starting in 30 minutes!\n\n📅 **${meeting.title}**\n🕐 Time: ${dateStr} at ${timeStr}\n📍 Location: ${meeting.location}\n📋 Purpose: ${meeting.purpose}\n\nLooking forward to meeting with you!`;

return [{
  json: {
    meetingId: meeting.id,
    schedulerPhone: schedulerPhone,
    schedulerMessage: schedulerMessage,
    contactPhone: contactPhone,
    contactMessage: contactMessage,
    contactName: meeting.contact_name,
    meetingTitle: meeting.title,
    meetingTime: `${dateStr} at ${timeStr}`
  }
}];

const data = $('Format Reminder Messages').first().json;

return [{
  json: {
    success: true,
    message: `✅ Reminder sent for meeting: ${data.meetingTitle}`,
    details: {
      meetingId: data.meetingId,
      contactName: data.contactName,
      meetingTime: data.meetingTime,
      schedulerNotified: !!data.schedulerPhone,
      contactNotified: true,
      timestamp: new Date().toISOString()
    }
  }
}];

// Format search results
const results = $input.all().flatMap(item => item.json);

// Get search term from previous node
const validateItems = $items("Validate Input1");
const searchTerm = (validateItems?.[0]?.json?.contact_name || 'Unknown').trim();

// Handle no results
if (!results || results.length === 0) {
  return [{
    json: {
      success: false,
      message: `❌ No contacts found matching "${searchTerm}".`,
      contacts: [],
      count: 0,
      intent: 'search'
    }
  }];
}

// Format contacts
const formattedContacts = results.map(contact => ({
  id: contact.id,
  name: contact.name || 'Unknown',
  phone_number: contact.phone_number || 'No phone',
  email: contact.email || '',
  company: contact.company || '',
  created_at: contact.created_at || null
}));

// Build message
let message = `✅ Found ${formattedContacts.length} contact${formattedContacts.length > 1 ? 's' : ''} matching "${searchTerm}":\n\n`;

formattedContacts.forEach((contact, index) => {
  message += `${index + 1}. **${contact.name}**\n`;
  message += `   📱 ${contact.phone_number}\n`;
  if (contact.email) message += `   ✉️ ${contact.email}\n`;
  if (contact.company) message += `   🏢 ${contact.company}\n`;
  message += `\n`;
});

return [{
  json: {
    success: true,
    message,
    contacts: formattedContacts,
    count: formattedContacts.length,
    intent: 'search',
    searchTerm
  }
}];

// Format insert response
const contact = $input.first().json;

return [{
  json: {
    success: true,
    message: `✅ Contact "${contact.name}" added successfully!`,
    intent: 'insert',
    contact: {
      id: contact.id,
      name: contact.name,
      phone_number: contact.phone_number,
      email: contact.email || '',
      company: contact.company || '',
      created_at: contact.created_at
    }
  }
}];

// Extract and validate input from AI agent
const rawInput = $input.first().json;

// Handle both wrapped (query) and flat formats
let input;
if (rawInput.query && typeof rawInput.query === 'object') {
  // Input is wrapped in "query" object
  input = rawInput.query;
} else {
  // Input is flat
  input = rawInput;
}

// Get intent (search or insert)
const intent = input.intent || 'search';

// Extract fields
const contactName = (input.contact_name || '').trim();
const agentId = (input.agent_id || '').trim();
const contactPhone = (input.contact_phone || '').trim();
const email = (input.email || '').trim();
const company = (input.company || '').trim();

// Validate required fields
if (!contactName || contactName.length < 2) {
  return [{
    json: {
      error: true,
      success: false,
      message: "❌ Please provide a valid contact name (2+ characters)."
    }
  }];
}

if (!agentId || agentId.length < 5) {
  return [{
    json: {
      error: true,
      success: false,
      message: "❌ Invalid or missing agent_id."
    }
  }];
}

// For INSERT, validate phone
if (intent === 'insert') {
  if (!contactPhone || contactPhone.length < 10) {
    return [{
      json: {
        error: true,
        success: false,
        message: "❌ Please provide a valid phone number (10+ digits)."
      }
    }];
  }
}

// Clean phone number (remove spaces, +, etc.)
function cleanPhone(phone) {
  if (!phone) return '';
  let cleaned = phone.replace(/[\s\-()]/g, ''); // Remove spaces, dashes, parentheses
  cleaned = cleaned.replace(/^\+/, ''); // Remove +
  if (cleaned.startsWith('0')) cleaned = '92' + cleaned.substring(1); // Handle 0 prefix for Pakistan
  return cleaned.replace(/\D/g, ''); // Keep only digits
}

const cleanedPhone = cleanPhone(contactPhone);

// Sanitize name
const sanitizedName = contactName
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') // Remove control chars
  .substring(0, 100);

// Return validated data
return [{
  json: {
    success: true,
    error: false,
    intent: intent,
    contact_name: sanitizedName,
    agent_id: agentId,
    contact_phone: cleanedPhone,
    email: email.substring(0, 100),
    company: company.substring(0, 100),
    searchPattern: `%${sanitizedName.toLowerCase()}%`
  }
}];

// Return error response from validation
const errorData = $input.first().json;

return [{
  json: {
    success: false,
    message: errorData.message,
    contacts: [],
    count: 0,
    intent: 'error'
  }
}];

// Prepare data specifically for WhatsApp API endpoint
// Get data from the "Should Track Thread?" node which has all the original data
const inputData = $('Should Track Thread?1').item.json;

// Map fields to match API expectations
const payload = {
  agentId: inputData.agentId || '',
  to: inputData.recipientPhone || inputData.numbers || inputData.phone_number || '',
  message: inputData.message || ''
};

// Clean phone number - ensure it's properly formatted
if (payload.to && payload.to.startsWith('+')) {
  payload.to = payload.to.substring(1);
}

return [{
  json: payload
}];

const aiResponse = $input.first().json;
const message = aiResponse.message || '';
const messageLower = message.toLowerCase();

// ============================================================
// AI MESSAGE DETECTION - PRIMARY CHECK
// ============================================================
// CRITICAL: Messages generated by the AI agent should NEVER be tracked
// This prevents infinite loops and database pollution
// ============================================================

// 1. Check for AI-GENERATED MESSAGE patterns
const aiGeneratedPatterns = [
  '👋 welcome to your personal business assistant',
  'please select an option:',
  'i can help you manage',
  'reply with the number',
  '1️⃣', '2️⃣', '3️⃣', '4️⃣', '5️⃣', '6️⃣',
  '📅 meeting options',
  'please select how you\'d like to view',
  '✅ message sent successfully',
  '✅ meeting scheduled',
  '✅ meeting invitation sent',
  '✅ contact',
  'added successfully',
  'invitation sent',
  'has been sent',
  'has been scheduled',
  'has been added',
  'meeting 1:',
  'meeting 2:',
  'here are your',
  'no meetings found',
  'retrieved',
  'search results',
  'i found the following',
  'i found',
  '📬',
  '🔄 erp/crm update feature',
  'returning to main menu',
  'returning to menu',
  '📨 message preview',
  'this message will be sent to',
  '📅 meeting invitation preview',
  'this invitation will be sent to',
  'please reply \'yes\' to send',
  'please reply \'yes\' to confirm',
  'reply \'yes\' to send',
  'or \'no\' to cancel',
  'meeting details:',
  'meeting details summary:',
  'organized by:',
  'the meeting invitation has been sent',
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━',
  'please provide:',
  'please provide the following',
  'i need the following information',
  'would you like to',
  'what would you like',
  'who would you like',
  'what is the',
  'which contact',
  'ready to add this contact',
  'contact not found'
];

// 2. Check for structured formatting (strong indicator of AI responses)
const hasMultipleBullets = (message.match(/•/g) || []).length >= 2;
const hasMultipleEmojis = (message.match(/[📅📨✅🔄👋💡📍📋📬]/g) || []).length >= 2;
const hasDecorators = message.includes('━━━━━━') || message.includes('═══════');
const hasStructuredNewlines = (message.match(/\n\n/g) || []).length >= 2;

// 3. Check message length (AI responses are typically longer than user input)
const isLongMessage = message.length > 200;

// 4. Check for AI pattern matches
const containsAIPattern = aiGeneratedPatterns.some(pattern => 
  messageLower.includes(pattern.toLowerCase())
);

// ============================================================
// FINAL AI MESSAGE DETECTION
// ============================================================
// A message is AI-generated if it matches ANY of these criteria:
const isAIGeneratedMessage = 
  containsAIPattern || // Contains known AI patterns
  (hasMultipleBullets && isLongMessage) || // Structured with bullets
  (hasMultipleEmojis && isLongMessage) || // Multiple emojis + long
  (hasDecorators) || // Has decorative lines
  (hasStructuredNewlines && isLongMessage) || // Well-formatted paragraphs
  (hasMultipleBullets && hasMultipleEmojis); // Structured formatting

// ============================================================
// THREAD TRACKING DECISION
// ============================================================
// AI-generated messages should NEVER be tracked
// This prevents them from being stored in message_threads table
// ============================================================

let shouldTrackThread = false;
let skipReason = null;

if (isAIGeneratedMessage) {
  // AI messages are NEVER tracked
  shouldTrackThread = false;
  skipReason = 'AI_GENERATED_MESSAGE';
} else {
  // For non-AI messages (actual user responses), apply normal tracking logic

  // Only track very specific question patterns that expect single answers
  const singleAnswerQuestions = [
    'who would you like to send a message to',
    'please provide their name',
    'what message would you like to send',
    'what is the meeting title',
    'what is the purpose',
    'what is the location'
  ];

  const isSingleAnswer = singleAnswerQuestions.some(pattern => 
    messageLower.includes(pattern)
  );

  // Even single-answer questions from AI shouldn't be tracked
  shouldTrackThread = isSingleAnswer && !isAIGeneratedMessage;
  skipReason = shouldTrackThread ? null : 'NOT_TRACKABLE_QUESTION';
}

// ============================================================
// RETURN RESULT
// ============================================================

return [{
  json: {
    ...aiResponse,
    shouldTrackThread: shouldTrackThread,
    isAIMessage: isAIGeneratedMessage,
    skipReason: skipReason,
    debug: {
      messageLength: message.length,
      containsAIPattern,
      hasMultipleBullets,
      hasMultipleEmojis,
      hasDecorators,
      hasStructuredNewlines,
      isLongMessage,
      isAIGeneratedMessage,
      finalDecision: shouldTrackThread,
      messagePreview: message.substring(0, 150)
    }
  }
}];

// Get agent data from the direct input (Get a row7 output)
const agentData = $input.first().json;

// Get message data from Switch2 node
let messageData = null;

try {
  messageData = $('Switch2').first().json;
} catch (e) {
  throw new Error('Could not find message data from Switch2 node');
}

// Validate required fields
if (!messageData || !messageData.messageId || !messageData.message_body) {
  throw new Error(`Invalid message data: ${JSON.stringify(messageData)}`);
}

if (!agentData || !agentData.id) {
  throw new Error(`Invalid agent data: ${JSON.stringify(agentData)}`);
}

// Determine if message is from agent (outgoing) or from customer (incoming)
const isFromAgent = messageData.isFromMe || false;

// Determine the actual sender and recipient based on message direction
const senderPhone = messageData.from;
const recipientPhone = messageData.to;
const customerPhone = isFromAgent ? recipientPhone : senderPhone;

return [{
  json: {
    // Core message data
    messageId: messageData.messageId,
    chatInput: messageData.message_body,
    messageBody: messageData.message_body,
    timestamp: messageData.timestamp,
    source: messageData.source,

    // Phone numbers and conversation
    senderPhone: senderPhone,
    recipientPhone: recipientPhone,
    customerPhone: customerPhone,
    conversationId: messageData.metadata?.conversationId || `${customerPhone}@s.whatsapp.net`,

    // Message metadata
    messageType: messageData.metadata?.messageType || 'text',
    isFromAgent: isFromAgent,
    isEmailResponse: messageData.email_response || false,

    // Agent data from Get a row7
    agentId: agentData.id,
    userId: agentData.user_id,
    agentName: agentData.agent_name,
    agentPhone: agentData.whatsapp_phone_number,
    agentOwnerName: agentData.agent_owner_name,
    agentPhoneNumber: agentData.agent_phone_number,

    // Agent configuration
    persona: agentData.persona,
    responseLanguages: agentData.response_languages,
    timezone: agentData.timezone,
    agentType: agentData.agent_type,
    agentStatus: agentData.status,

    // Additional agent info
    avatarUrl: agentData.avatar_url || null,
    integrationEndpoints: agentData.integration_endpoints || [],
    uploadedFiles: agentData.uploaded_files || [],

    // Webhook info
    webhookSource: messageData.headers?.['x-webhook-source'] || 'unknown',

    // AI Agent Context - Formatted for better prompt injection
    agentContext: {
      name: agentData.agent_name,
      owner: agentData.agent_owner_name,
      ownerPhone: agentData.agent_phone_number,
      persona: agentData.persona,
      languages: agentData.response_languages,
      timezone: agentData.timezone,
      customerPhone: customerPhone,
      conversationDirection: isFromAgent ? 'outgoing' : 'incoming',
      messageSource: messageData.source
    }
  }
}];

