const aiOutput = $input.first().json;
const messageData = $('Prepare AI Context1').item.json;

// Extract the text output from AI agent
let responseText = '';

if (typeof aiOutput.output === 'string') {
  responseText = aiOutput.output;
} else if (aiOutput.text) {
  responseText = aiOutput.text;
} else if (aiOutput.content) {
  responseText = aiOutput.content;
} else {
  responseText = 'I apologize, I could not process your request. Please try again.';
}

return [{
  json: {
    message: responseText.trim(),
    numbers: messageData.senderPhone,
    messageType: 'TEXT',
    agentId: messageData.agentId,
    userId: messageData.userId,
    recipientPhone: messageData.senderPhone.replace('+', ''),
    originalMessageId: messageData.messageId,
    conversationId: messageData.conversationId
  }
}];

const thread = $json.threadData;
const reply = $json.originalMessage;

return [{
  json: {
    threadId: thread.threadId,
    originalMessageId: thread.originalMessageId,
    originalSenderPhone: thread.originalSender,
    replyFromPhone: reply.senderPhone.replace('+', ''),
    senderName: reply.senderName || 'Unknown',
    replyContent: reply.message,
    replyMessageId: reply.messageId,
    agentId: reply.agentId,
    userId: reply.userId,
    originalConversationId: thread.originalConversationId,
    currentConversationId: reply.conversationId,
    originalMessage: thread.originalMessage
  }
}];

const data = $('Process Reply').first().json;

const notificationMessage = `📬 *Reply from ${data.senderName || 'Unknown'}* (+${data.replyFromPhone})

💬 *Reply:* "${data.replyContent}"

📝 *Original Message:* "${data.originalMessage || 'N/A'}"

🕐 ${new Date().toLocaleString('en-US', { timeZone: 'Asia/Karachi' })}`;

return [{
  json: {
    numbers: $('IF Reply?').first().json.originalMessage.agentOwnerPhone,  // Changed from originalSenderPhone to replyFromPhone
    message: notificationMessage,
    messageType: 'TEXT',
    agentId: data.agentId,

    // Additional metadata
    threadId: data.threadId,
    replyMessageId: data.replyMessageId,
    originalMessageId: data.originalMessageId
  }
}];

const data = $('Process Reply').first().json;

const confirmationMessage = `✅ *Reply Acknowledged*

Hi ${data.senderName || 'there'}! 👋

Your message has been delivered to the sender.

Thank you for your response!`;

return [{
  json: {
    numbers: data.replyFromPhone,
    message: confirmationMessage,
    messageType: 'TEXT',
    agentId: data.agentId,

    // Additional metadata
    senderName: data.senderName,
    threadId: data.threadId,
    replyMessageId: data.replyMessageId
  }
}];

// Get the meeting data from the previous node (Check for Pending Meeting)
const meetingData = $input.first().json;

// Get the original message data from IF Reply? node
let messageData = {};
let agentId = null;

try {
  const replyData = $('IF Reply?').first().json;  // Fixed: removed trailing space
  messageData = replyData.originalMessage || {};
  agentId = replyData.originalMessage?.agentId || replyData.agentId;
} catch (e) {
  console.log('Could not access IF Reply? node:', e.message);
}

// Fallback: try to get data from Log Message to DB if IF Reply? fails
if (!agentId) {
  try {
    const logData = $('Log Message to DB').first().json;
    agentId = logData.agent_id || logData.agentId;
  } catch (e) {
    console.log('Could not access Log Message to DB node:', e.message);
  }
}

// Check if we have a pending meeting
const hasPendingMeeting = meetingData && meetingData.contact_phone;

// Return combined data
return [{
  json: {
    hasPendingMeeting: !!hasPendingMeeting,
    meeting: hasPendingMeeting ? meetingData : null,
    message: messageData,
    agentId: agentId,

    // Additional useful data
    senderPhone: messageData.senderPhone || meetingData.contact_phone,
    messageText: messageData.message,
    timestamp: messageData.timestamp
  }
}];

// --- Extract Inputs ---
const input = $input.first().json;
const message = input.message?.message || null;  // Fixed: Get message from input instead of non-existent node
const agentId = input.agentId || null;

// --- Validate Meeting Data ---
if (!input || !input.meeting) {
  return [{
    json: {
      error: true,
      success: false,
      message: '❌ No meeting data found in input.'
    }
  }];
}

const meeting = input.meeting;
const hasPendingMeeting = !!input.hasPendingMeeting;
const meetingId = meeting.id || null;
const userId = meeting.user_id || null;
const title = (meeting.title || '').trim();
const dateTime = (meeting.date_time || '').trim();
const purpose = (meeting.purpose || '').trim();
const location = (meeting.location || 'Virtual').trim();
const contactName = (meeting.contact_name || '').trim();
const contactPhone = (meeting.contact_phone || '').trim();
const meetingStatus = (meeting.status || '').trim();

const errors = [];
if (!meetingId) errors.push('Meeting ID is required.');
if (!userId) errors.push('User ID is required.');
if (!agentId) errors.push('Agent ID is required.');
if (!contactName) errors.push('Contact name is required.');
if (!contactPhone || contactPhone.length < 10 || isNaN(Number(contactPhone))) {
  errors.push('Valid contact phone number required (numeric, min 10 digits).');
}
if (!title) errors.push('Meeting title is required.');
if (!dateTime) errors.push('Meeting date and time required.');
if (!purpose) errors.push('Meeting purpose is required.');

if (errors.length > 0) {
  return [{
    json: {
      error: true,
      success: false,
      message: `❌ Validation failed:\n${errors.join('\n')}`
    }
  }];
}

// --- Construct Output for Subworkflow ---
return [{
  json: {
    hasPendingMeeting,
    meetingId,
    userId,
    agentId,
    contactName,
    contactPhone: `+${contactPhone.replace(/\+/g, '')}`,
    title,
    dateTime,
    purpose,
    location,
    meetingStatus,
    createdAt: meeting.created_at || null,
    message,
    messageSuccess: input.message?.success || false,
    timestamp: new Date().toISOString(),
    success: true
  }
}];

// Get data from both nodes
const agentData = $('Switch11').first().json;
const messageData = $('Parse & Validate Message').first().json;

return [{
  json: {
    // Core message data
    messageId: messageData.messageId,
    conversationId: messageData.conversationId,
    senderPhone: messageData.senderPhone?.replace('+', '') || '',
    senderName: messageData.senderName,
    message: messageData.message,
    timestamp: messageData.timestamp,

    // IDs
    agentId: messageData.agentId,
    userId: messageData.userId,

    // Phone numbers
    agentPhone: messageData.agentPhone?.replace('+', '') || '',
    agentOwnerPhone: agentData.agent_phone_number?.replace('+', '') || '',

    // Names
    agentName: agentData.agent_name,
    agentOwnerName: agentData.agent_owner_name,

    // Agent configuration
    persona: agentData.persona,
    responseLanguages: agentData.response_languages,
    timezone: agentData.timezone,

    // Message metadata
    messageType: messageData.messageType,
    direction: messageData.direction,
    source: messageData.source,
    platform: messageData.platform,
    remoteJid: messageData.remoteJid
  }
}];

const threadResult = $input.first().json || {};
const hasActiveThread = Boolean(threadResult && threadResult.id);

// Try to get original message from Check if Reply to Thread node
let originalMessage = null;
try {
  const previousNode = $('Check if Reply to Thread').first().json;
  originalMessage = previousNode?.originalMessage || previousNode;
} catch (e) {
  console.log('Error accessing Check if Reply to Thread node');
}

// Validate we have the required data
const hasRequiredData = originalMessage && 
                       originalMessage.conversationId && 
                       threadResult.recipient_phone;

// Helper function to clean phone numbers
const cleanPhone = (phone) => {
  if (!phone) return '';
  return String(phone)
    .replace(/\+/g, '')
    .replace(/@s\.whatsapp\.net/g, '')
    .replace(/@.*$/g, '')
    .trim();
};

// Check if this is actually a reply to an active thread
let isActualReply = false;
let threadData = null;

if (hasActiveThread && hasRequiredData) {
  const currentSender = cleanPhone(originalMessage.conversationId);
  const threadRecipient = cleanPhone(threadResult.recipient_phone);
  const agentMatches = originalMessage.agentId === threadResult.agent_id;

  if (currentSender === threadRecipient && agentMatches) {
    isActualReply = true;
    threadData = {
      threadId: threadResult.id,
      originalMessageId: threadResult.original_message_id,
      originalMessage: threadResult.original_message,
      originalSender: threadResult.sender_phone,
      originalConversationId: threadResult.original_conversation_id,
      recipientPhone: threadResult.recipient_phone,
      timeSinceSent: threadResult.sent_at ? new Date() - new Date(threadResult.sent_at) : null
    };
  }
}

return [{
  json: {
    isReply: isActualReply,
    threadData: threadData,
    originalMessage: originalMessage || {},
    debug: {
      hasThread: hasActiveThread,
      hasRequiredData: hasRequiredData,
      currentSender: originalMessage?.conversationId ? cleanPhone(originalMessage.conversationId) : 'N/A',
      threadRecipient: threadResult?.recipient_phone ? cleanPhone(threadResult.recipient_phone) : 'N/A',
      phonesMatch: hasRequiredData ? cleanPhone(originalMessage.conversationId) === cleanPhone(threadResult.recipient_phone) : false,
      agentMatch: originalMessage?.agentId === threadResult?.agent_id,
      error: !hasRequiredData ? 'Missing required data (conversationId or recipient_phone)' : null
    }
  }
}];

// Prepare data specifically for WhatsApp API endpoint
// Get data from the "Should Track Thread?" node which has all the original data
const inputData = $('Should Track Thread?3').item.json;

