  responseText = aiResponse.output[0]?.content[0]?.text || '';
}
// Handle direct text response
else if (typeof aiResponse === 'string') {
  responseText = aiResponse;
}
// Handle text property
else if (aiResponse.text) {
  responseText = aiResponse.text;
}
// Handle content array
else if (aiResponse.content && Array.isArray(aiResponse.content)) {
  responseText = aiResponse.content[0]?.text || '';
}
// Check if already the correct format
else if ((aiResponse.agentId || aiResponse.accountId) && aiResponse.to && aiResponse.message) {
  return [{
    json: {
      agentId: aiResponse.agentId || aiResponse.accountId,
      to: aiResponse.to,
      message: aiResponse.message,
      generatedAt: new Date().toISOString(),
      draftStatus: 'generated'
    }
  }];
}
// Fallback
else {
  responseText = JSON.stringify(aiResponse);
}

// Ensure responseText is a string
responseText = String(responseText).trim();

// Remove markdown code blocks if present
responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

// Parse the JSON
let emailDraft;
try {
  emailDraft = JSON.parse(responseText);
} catch (e) {
  // If parsing fails, try to extract JSON from the response
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      emailDraft = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      console.log('Raw response:', responseText);
      throw new Error('Could not parse AI response as JSON: ' + e2.message);
    }
  } else {
    console.log('Raw response:', responseText);
    throw new Error('Could not parse AI response as JSON: ' + e.message);
  }
}

// Validate required fields
const agentId = emailDraft.agentId || emailDraft.accountId;
if (!agentId || !emailDraft.to || !emailDraft.message) {
  throw new Error('Missing required fields in parsed email draft. Expected: agentId, to, message. Received: ' + JSON.stringify(emailDraft));
}

// Return structured output
return [{
  json: {
    agentId: agentId,
    to: emailDraft.to,
